import React, { useState, useEffect } from 'react';
import { FiMessageCircle } from 'react-icons/fi';
import './ChatSidebar.css';

const dummyChats = [
  { sender: 'You', message: "What should I eat before my long run?" },
  { sender: 'Coach', message: "Go for something high-carb and easy to digest, like toast with peanut butter and a banana." },
  { sender: 'You', message: "How do I avoid shin splints?" },
  { sender: 'Coach', message: "Make sure you're not ramping up mileage too fast. Add strength work and check your shoes." },
  { sender: 'You', message: "Should I run if I'm sore from lifting?" },
  { sender: 'Coach', message: "Light running is fine, but listen to your body. Prioritize recovery if you're very sore." }
];

export default function ChatSidebar() {
  const [open, setOpen] = useState(false);

  useEffect(() => {
    const handleKey = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'o') {
        e.preventDefault();
        setOpen(prev => !prev);
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, []);

  return (
    <>
      {/* Toggle Icon */}
      <div className="chat-toggle-icon" onClick={() => setOpen(!open)}>
        <FiMessageCircle size={28} />
      </div>

      {/* Sidebar */}
      <div className={`chat-sidebar ${open ? 'open' : ''}`}>
        <h2>Chat History</h2>
        <div className="chat-messages">
          {dummyChats.map((chat, i) => (
            <div
              key={i}
              className={`chat-bubble ${chat.sender === 'You' ? 'user' : 'coach'}`}
            >
              <strong>{chat.sender}</strong>
              <p>{chat.message}</p>
            </div>
          ))}
        </div>
      </div>
    </>
  );
}
